#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int a,b; scanf("%d %d",&a,&b);
        int x = a ^ b;
        int cnt = 0;
        while(x){
            x &= (x-1);
            cnt++;
        }
        printf("%d\n",cnt);
    }
    return 0;
}

